11.query:
fetch logs 
| filter k8s.container.name=="product-catalog" and isNotNull(trace_id)
| lookup [
  fetch bizevents
  | filter event.type=="astroshop.web.checkout_failure" 
], sourceField:trace_id, lookupField:trace_id
| filterOut isNull(lookup.trace_id)
| parse content,
"JSON {
    JSON {
        STRING:Type,
        STRING:Value
    }:Body
}(flat=true)
"
| fieldsAdd Body[Value]
| parse Body[Value], "LD 'product.id=\"' LD:product.id '\"'"
| summarize count=count(), by:{product.id}
| sort count desc
| filterOut isNull(product.id)

17.query:
fetch bizevents
| filter event.type == "astroshop.web.checkout_success"
| dedup { orderId }
| parse items, """ARRAY{DATA 'quantity' LD LONG:quantity LD 'product'  DATA 'id\":' DQS:productId DATA 'name\":' DQS:productName DATA 'price' LD LONG:units DATA 'nanos' LD LONG:nanos DATA JSON_ARRAY:categories}{0,100}:data"""
| expand data
| fieldsFlatten data, fields: { quantity, productName }
| lookup [
    fetch bizevents, from: -1d, to: now()
    | filter event.type == "exchangeRates.fromUSD"
    | sort timestamp desc
], sourceField: shippingCost.currencyCode, lookupField: to, fields: { rate }
| summarize quantity = sum(quantity), by: { productName }
| sort quantity desc

30.query:
fetch bizevents
| filter event.type == "astroshop.web.checkout_success"
| dedup { orderId }
// Parse the items field as the get stringified during bizevent extraction
| parse items, """JSON_ARRAY:items"""
// Explode out array
| expand items
// Get just the fields you care about
| fields shippingCost.currencyCode
      , productId = items[item][productId]
      , quantity = items[item][quantity]
      , productName = items[item][product][name]
      , units = items[item][product][priceUsd][units]
      // calculate unit cost
      , unitCost = toDouble(items[item][product][priceUsd][units]) / 1000000000.0
// FYI: your original query was `(units + cents) * quantity`, 
//   but you shouldn't multiply unit and unitCost not add to get per order quantity cost?
| fieldsAdd subTotalAmount = (unitCost * units) + quantity
// Lookup Exchange Rate
| lookup [
    fetch bizevents, from: -1d, to: now()
    | filter event.type == "exchangeRates.fromUSD"
    | sort timestamp desc
], sourceField: shippingCost.currencyCode, lookupField: to, fields: { rate }
| fieldsAdd subTotalAmountUSD = subTotalAmount / toDouble(rate)
| summarize subTotalAmountUSD = sum(subTotalAmountUSD), by: { productName, productId }
| fieldsAdd subTotalRev = subTotalAmountUSD
| sort subTotalAmountUSD desc

4.query:
fetch bizevents
| filter event.type == "astroshop.web.checkout_success"
| dedup { orderId }
| parse items, """ARRAY{DATA 'quantity' LD LONG:quantity LD 'product'  DATA 'id\":' DQS:productId DATA 'price' LD LONG:units DATA 'nanos' LD LONG:nanos DATA JSON_ARRAY:categories}{0,100}:data"""
| expand data
| fieldsFlatten data, fields: { quantity, categories }
| lookup [
    fetch bizevents, from: -1d, to: now()
    | filter event.type == "exchangeRates.fromUSD"
    | sort timestamp desc
], sourceField: shippingCost.currencyCode, lookupField: to, fields: { rate }
| fieldsAdd categories = replacePattern(toString(categories), """[\[\]\"]""", "")
| summarize quantity = sum(quantity), by: { categories }
